INSERT  IGNORE INTO `article` (`id`, `author`, `content`, `created_date`, `image`, `modified_date`, `short_content`, `status`, `title`, `category_id`, `user_id`) VALUES (1,'─Éß╗Öi ng┼⌐ t╞░ vß║Ñn Moto Shop','<h2><strong>1. X├íc ─æß╗ïnh mß╗Ñc ─æ├¡ch sß╗¡ dß╗Ñng</strong></h2>\r\n<p>Tr╞░ß╗¢c khi chß╗ìn xe, h├úy tß╗▒ hß╗Åi: bß║ín ─æi xe chß╗º yß║┐u ─æß╗â l├ám g├¼? ─Éi l├ám h├áng ng├áy trong phß╗æ? Chß║íy ─æ╞░ß╗¥ng d├ái li├¬n tß╗ënh? Hay chß╗ë di chuyß╗ân ngß║»n trong khu d├ón c╞░? Mß╗Ñc ─æ├¡ch sß╗¡ dß╗Ñng quyß║┐t ─æß╗ïnh h╞ín 50% viß╗çc bß║ín n├¬n chß╗ìn xe loß║íi g├¼.</p>\r\n<ul>\r\n  <li><strong>─Éi phß╗æ h├áng ng├áy:</strong> Xe tay ga (scooter) l├á lß╗▒a chß╗ìn l├╜ t╞░ß╗ƒng ΓÇö tiß╗çn lß╗úi, tiß║┐t kiß╗çm x─âng, dß╗à giß╗» ─æß╗ô.</li>\r\n  <li><strong>─É╞░ß╗¥ng d├ái, ─æß╗ïa h├¼nh xß║Ñu:</strong> Xe sß╗æ hoß║╖c xe c├┤n tay cho cß║úm gi├íc l├íi chß╗º ─æß╗Öng h╞ín, bß╗ün bß╗ë h╞ín.</li>\r\n  <li><strong>Mang v├íc h├áng h├│a:</strong> Xe sß╗æ truyß╗ün thß╗æng nh╞░ Honda Wave, Suzuki Axelo c├│ ─æß╗Ö bß╗ün cao v├á chi ph├¡ bß║úo d╞░ß╗íng thß║Ñp.</li>\r\n</ul>\r\n<h2><strong>2. C├ón nhß║»c ng├ón s├ích thß╗▒c tß║┐</strong></h2>\r\n<p>Gi├í xe chß╗ë l├á mß╗Öt phß║ºn ΓÇö bß║ín cß║ºn t├¡nh th├¬m chi ph├¡ ─æ─âng k├╜, bß║úo hiß╗âm, phß╗Ñ kiß╗çn (m┼⌐ bß║úo hiß╗âm, kh├│a chß╗æng trß╗Öm) v├á dß╗▒ ph├▓ng bß║úo d╞░ß╗íng 6 th├íng ─æß║ºu. Mß╗Öt chiß║┐c xe tß║ºm 30ΓÇô45 triß╗çu ─æß╗ông th╞░ß╗¥ng ph├╣ hß╗úp vß╗¢i ─æa sß╗æ ng╞░ß╗¥i d├╣ng phß╗ò th├┤ng.</p>\r\n<h2><strong>3. ╞»u ti├¬n th╞░╞íng hiß╗çu c├│ hß╗ç thß╗æng bß║úo h├ánh rß╗Öng</strong></h2>\r\n<p>Honda v├á Yamaha hiß╗çn c├│ mß║íng l╞░ß╗¢i HEAD/YEAD trß║úi rß╗Öng to├án quß╗æc, gi├║p viß╗çc bß║úo d╞░ß╗íng v├á thay thß║┐ phß╗Ñ t├╣ng ch├¡nh h├úng dß╗à d├áng h╞ín. ─É├óy l├á yß║┐u tß╗æ quan trß╗ìng, ─æß║╖c biß╗çt nß║┐u bß║ín ß╗ƒ tß╗ënh hoß║╖c th╞░ß╗¥ng xuy├¬n di chuyß╗ân li├¬n v├╣ng.</p>\r\n<h2><strong>4. Kiß╗âm tra kß╗╣ tr╞░ß╗¢c khi nhß║¡n xe</strong></h2>\r\n<p>D├╣ mua xe mß╗¢i hay xe c┼⌐, h├úy kiß╗âm tra c├íc ─æiß╗âm sau:</p>\r\n<ul>\r\n  <li>Sß╗æ khung, sß╗æ m├íy khß╗¢p vß╗¢i giß║Ñy tß╗¥</li>\r\n  <li>─É├¿n tr╞░ß╗¢c/sau, xi nhan hoß║ít ─æß╗Öng b├¼nh th╞░ß╗¥ng</li>\r\n  <li>Phanh tr╞░ß╗¢c/sau ─ân ─æß╗üu, kh├┤ng bß╗ï lß╗Ång</li>\r\n  <li>Kh├┤ng c├│ m├╣i kh├⌐t tß╗½ ─æß╗Öng c╞í hay hß╗Öp sß╗æ</li>\r\n  <li>Lß╗æp xe kh├┤ng bß╗ï m├▓n, kh├┤ng ph├¼nh v├í</li>\r\n</ul>\r\n<h2><strong>5. ─Éß╗ìc kß╗╣ hß╗úp ─æß╗ông v├á giß║Ñy tß╗¥ xe</strong></h2>\r\n<p>─Éß║úm bß║úo bß║ín nhß║¡n ─æß╗º: h├│a ─æ╞ín mua xe, phiß║┐u bß║úo h├ánh, sß╗ò tay h╞░ß╗¢ng dß║½n sß╗¡ dß╗Ñng. Vß╗¢i xe c┼⌐, cß║ºn kiß╗âm tra c├á vß║╣t (giß║Ñy ─æ─âng k├╜ xe) ch├¡nh chß╗º v├á x├íc nhß║¡n kh├┤ng bß╗ï thß║┐ chß║Ñp ng├ón h├áng tr╞░ß╗¢c khi thanh to├ín.</p>','2026-06-14 09:30:00','blog_1.jpg','2026-05-05 17:02:01','<p>Mua xe m├íy lß║ºn ─æß║ºu dß╗à bß╗ï \"hoa mß║»t\" tr╞░ß╗¢c h├áng chß╗Ñc mß║½u xe tr├¬n thß╗ï tr╞░ß╗¥ng. B├ái viß║┐t n├áy tß╗òng hß╗úp 5 kinh nghiß╗çm thß╗▒c tß║┐ gi├║p bß║ín chß╗ìn ─æ╞░ß╗úc chiß║┐c xe ph├╣ hß╗úp nhß║Ñt vß╗¢i nhu cß║ºu v├á ng├ón s├ích.</p>',1,'5 Kinh nghiß╗çm chß╗ìn mua xe m├íy kh├┤ng thß╗â bß╗Å qua',35,2),(2,'─Éß╗Öi ng┼⌐ kß╗╣ thuß║¡t Moto Shop','<h2><strong>Tß║íi sao phß║úi bß║úo d╞░ß╗íng ─æß╗ïnh kß╗│?</strong></h2>\r\n<p>Nhiß╗üu chß╗º xe th╞░ß╗¥ng bß╗Å qua lß╗ïch bß║úo d╞░ß╗íng v├¼ thß║Ñy xe vß║½n chß║íy b├¼nh th╞░ß╗¥ng. Thß╗▒c tß║┐, c├íc bß╗Ö phß║¡n b├¬n trong ─æß╗Öng c╞í ─æang m├▓n dß║ºn theo tß╗½ng kilomet. Bß║úo d╞░ß╗íng ─æ├║ng lß╗ïch gi├║p ph├ít hiß╗çn sß╗¢m hß╗Ång h├│c, tiß║┐t kiß╗çm chi ph├¡ sß╗¡a chß╗»a lß╗¢n vß╗ü sau.</p>\r\n<h2><strong>Lß╗ïch bß║úo d╞░ß╗íng chuß║⌐n theo km</strong></h2>\r\n<h3><strong>Mß╗ùi 1.000 km (hoß║╖c 1 th├íng)</strong></h3>\r\n<ul>\r\n  <li>Kiß╗âm tra ├íp suß║Ñt lß╗æp tr╞░ß╗¢c/sau</li>\r\n  <li>Kiß╗âm tra mß╗⌐c dß║ºu nhß╗¢t</li>\r\n  <li>Kiß╗âm tra phanh, ─æ├¿n, xi nhan</li>\r\n  <li>Vß╗ç sinh s╞í bß╗Ö xe</li>\r\n</ul>\r\n<h3><strong>Mß╗ùi 3.000 km (hoß║╖c 3 th├íng)</strong></h3>\r\n<ul>\r\n  <li><strong>Thay dß║ºu nhß╗¢t</strong> ΓÇö ─æ├óy l├á viß╗çc quan trß╗ìng nhß║Ñt, kh├┤ng n├¬n